  "files": {
    "Cargo.toml": "[package]
name = "monthly_category_summary"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub category: &'static str,
    pub amount: i32,
}

pub fn category_summary(entries: &[Entry]) -> String {
    let mut totals = BTreeMap::<&str, i32>::new();
    for entry in entries {
        *totals.entry(entry.category).or_insert(0) += entry.amount;
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    rows.into_iter()
        .map(|(category, total)| format!("{}:{}", category, total))
        .collect::<Vec<_>>()
        .join("\n")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn sorts_by_total_desc_then_name_and_skips_zero_totals() {
        let entries = [
            Entry { category: "ops", amount: 5 },
            Entry { category: "sales", amount: 8 },
            Entry { category: "ops", amount: 3 },
            Entry { category: "rnd", amount: -2 },
            Entry { category: "sales", amount: 2 },
            Entry { category: "support", amount: 10 },
            Entry { category: "rnd", amount: 2 },
        ];

        assert_eq!(category_summary(&entries), "ops:8\nsales:10\nsupport:10");
    }

    #[test]
    fn tie_on_total_uses_category_name() {
        let entries = [
            Entry { category: "beta", amount: 4 },
            Entry { category: "alpha", amount: 4 },
            Entry { category: "gamma", amount: 1 },
        ];

        assert_eq!(category_summary(&entries), "alpha:4\nbeta:4\ngamma:1");
    }
}
