    rows.into_iter()
        .map(|(category, total)| format!("{}:{}", category, total))
        .collect::<Vec<_>>()
        .join("\n")
",
      "replace": "    let mut rows: Vec<_> = totals.into_iter().filter(|(_, total)| *total != 0).collect();
    rows.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(b.0)));

    rows.into_iter()
