    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum State {
    Draft,
    Submitted,
    Approved,
    Rejected,
    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
    Archive,
    Reopen,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    state: State,
    revision: u32,
    approved_at_revision: Option<u32>,
    archived: bool,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            state: State::Draft,
            revision: 0,
            approved_at_revision: None,
            archived: false,
        }
    }

    pub fn state(&self) -> State {
        self.state
    }

    pub fn revision(&self) -> u32 {
        self.revision
    }

    pub fn approved_at_revision(&self) -> Option<u32> {
        self.approved_at_revision
    }

    pub fn is_archived(&self) -> bool {
        self.archived
    }

    pub fn apply(&mut self, event: Event) -> bool {
        match event {
            Event::Submit => {
                if self.state == State::Draft || self.state == State::Rejected {
                    self.state = State::Submitted;
                    true
                } else {
                    false
                }
            }
            Event::Approve => {
                if self.state == State::Submitted {
                    self.state = State::Approved;
                    self.approved_at_revision = Some(self.revision);
                    true
                } else {
                    false
                }
            }
            Event::Reject => {
                if self.state == State::Submitted {
                    self.state = State::Rejected;
                    true
                } else {
                    false
                }
            }
            Event::Revise => {
                if self.state != State::Archived {
                    self.revision += 1;
                    self.state = State::Draft;
                    true
                } else {
                    false
                }
            }
            Event::Archive => {
                self.archived = true;
                self.state = State::Archived;
                true
            }
            Event::Reopen => {
                if self.archived {
                    self.archived = false;
                    self.state = State::Submitted;
                    true
                } else {
                    false
                }
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::{Event, State, Ticket};

    #[test]
    fn rejected_items_can_be_revised_and_resubmitted() {
        let mut t = Ticket::new();
        assert!(t.apply(Event::Submit));
        assert!(t.apply(Event::Reject));
        assert!(t.apply(Event::Revise));
        assert_eq!(t.state(), State::Draft);
        assert_eq!(t.revision(), 1);
        assert!(t.apply(Event::Submit));
        assert_eq!(t.state(), State::Submitted);
    }

    #[test]
    fn approved_revision_is_cleared_after_changes() {
        let mut t = Ticket::new();
        assert!(t.apply(Event::Submit));
        assert!(t.apply(Event::Approve));
        assert_eq!(t.approved_at_revision(), Some(0));

        assert!(t.apply(Event::Revise));
        assert_eq!(t.state(), State::Draft);
        assert_eq!(t.revision(), 1);
        assert_eq!(t.approved_at_revision(), None);
    }

    #[test]
    fn archive_only_allowed_from_terminal_review_states() {
        let mut fresh = Ticket::new();
        assert!(!fresh.apply(Event::Archive));
        assert_eq!(fresh.state(), State::Draft);
        assert!(!fresh.is_archived());

        let mut submitted = Ticket::new();
        assert!(submitted.apply(Event::Submit));
        assert!(!submitted.apply(Event::Archive));
        assert_eq!(submitted.state(), State::Submitted);
        assert!(!submitted.is_archived());

        let mut approved = Ticket::new();
        assert!(approved.apply(Event::Submit));
        assert!(approved.apply(Event::Approve));
        assert!(approved.apply(Event::Archive));
        assert_eq!(approved.state(), State::Archived);
        assert!(approved.is_archived());

        let mut rejected = Ticket::new();
        assert!(rejected.apply(Event::Submit));
        assert!(rejected.apply(Event::Reject));
        assert!(rejected.apply(Event::Archive));
        assert_eq!(rejected.state(), State::Archived);
        assert!(rejected.is_archived());
    }

    #[test]
    fn reopen_returns_archived_ticket_to_draft_without_losing_revision() {
        let mut t = Ticket::new();
        assert!(t.apply(Event::Submit));
        assert!(t.apply(Event::Approve));
        assert!(t.apply(Event::Archive));
        assert!(t.apply(Event::Reopen));
        assert_eq!(t.state(), State::Draft);
        assert_eq!(t.revision(), 0);
        assert!(!t.is_archived());
        assert_eq!(t.approved_at_revision(), None);
    }

    #[test]
    fn cannot_revise_archived_ticket_until_reopened() {
        let mut t = Ticket::new();
        assert!(t.apply(Event::Submit));
        assert!(t.apply(Event::Reject));
        assert!(t.apply(Event::Archive));
        assert!(!t.apply(Event::Revise));
        assert_eq!(t.state(), State::Archived);
        assert_eq!(t.revision(), 0);
    }
}
"
  },
