pub enum Status {
    Draft,
    Active,
    Suspended,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Suspend,
    Resume,
    Reopen,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub status: Status,
    pub approvals: u8,
    pub rejections: u8,
    pub history: Vec<Status>,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            status: Status::Draft,
            approvals: 0,
            rejections: 0,
            history: vec![Status::Draft],
        }
    }

    pub fn apply(&mut self, event: Event) {
        match event {
            Event::Submit => {
                self.status = Status::Draft;
                self.approvals = 0;
                self.rejections = 0;
            }
            Event::Approve => {
                self.approvals += 1;
                if self.approvals >= 2 {
                    self.status = Status::Active;
                }
            }
            Event::Reject => {
                self.rejections += 1;
                self.status = Status::Closed;
            }
            Event::Suspend => {
                self.status = Status::Suspended;
            }
            Event::Resume => {
                self.status = Status::Active;
            }
            Event::Reopen => {
                self.status = Status::Draft;
            }
        }
        self.history.push(self.status);
    }
}

pub fn run_events(events: &[Event]) -> Ticket {
    let mut ticket = Ticket::new();
    for &event in events {
        ticket.apply(event);
    }
    ticket
}

