pub fn merge_config(
    defaults: Config,
    file: Option<PartialConfig>,
    env: Option<PartialConfig>,
    cli: Option<PartialConfig>,
) -> Config {
    let mut cfg = defaults;

    if let Some(f) = file {
        if let Some(host) = f.host {
            cfg.host = host;
        }
        if let Some(port) = f.port {
            cfg.port = port;
