        if let Some(e) = env {
            if let Some(host) = e.host {
                cfg.host = host;
            }
            if let Some(port) = e.port {
                cfg.port = port;
            }
            if let Some(verbose) = e.verbose {
                cfg.verbose = verbose;
            }
        }
    } else if let Some(e) = env {
        if let Some(host) = e.host {
            cfg.host = host;
        }
        if let Some(port) = e.port {
            cfg.port = port;
        }
        if let Some(verbose) = e.verbose {
            cfg.verbose = verbose;
        }
    }

    if let Some(c) = cli {
        if let Some(host) = c.host {
            cfg.host = host;
        }
        if let Some(port) = c.port {
            cfg.port = port;
        }
        if let Some(verbose) = c.verbose {
