pub fn merge_config(base: &Config, env: &ConfigPatch, cli: &ConfigPatch) -> Config {
    let timeout_ms = cli
        .timeout_ms
        .or(env.timeout_ms)
        .unwrap_or(base.timeout_ms);

    let endpoint = cli
        .endpoint
        .as_ref()
        .or(env.endpoint.as_ref())
        .cloned()
        .unwrap_or_else(|| base.endpoint.clone());

    let retries = cli
        .retries
        .flatten()
        .or(env.retries.flatten())
        .unwrap_or(base.retries);

    Config {
        timeout_ms,
        endpoint,
        retries,
    }
}

