pub fn classify(msg: Message) -> &'static str {
    match msg {
        Message::Connect => "info",
        Message::Disconnect => "info",
        Message::Data(size) if size == 0 => "empty",
        Message::Data(_) => "info",
        Message::Error { code, .. } if code >= 500 => "fatal",
        Message::Error { transient: true, .. } => "retry",
        Message::Error { .. } => "fatal",
    }
}

