T2|Closed|owner=carol|active=0|closed=1|invalid=1
T3|New|owner=dana|active=1|closed=0|invalid=2",
  "files": {
    "Cargo.toml": "[package]
name = "ticket_audit"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    New,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Clone, Debug)]
struct Ticket {
    owner: String,
    status: Status,
    invalid: u32,
}

fn apply_event(ticket: &mut Ticket, event: &str) {
    let mut parts = event.split(':');
    let kind = parts.next().unwrap();
    let arg = parts.next();

    match kind {
        "assign" => {
            if let Some(name) = arg {
                ticket.owner = name.to_string();
            } else {
                ticket.invalid += 1;
            }
        }
        "start" => {
            ticket.status = Status::InProgress;
        }
        "block" => {
            if ticket.status == Status::InProgress {
                ticket.status = Status::Blocked;
            } else {
                ticket.invalid += 1;
            }
        }
        "resume" => {
            if ticket.status == Status::Blocked {
                ticket.status = Status::Resolved;
            } else {
                ticket.invalid += 1;
            }
        }
        "resolve" => {
            ticket.status = Status::Resolved;
        }
        "close" => {
            if ticket.status == Status::Resolved || ticket.status == Status::New {
                ticket.status = Status::Closed;
            } else {
                ticket.invalid += 1;
            }
        }
        _ => ticket.invalid += 1,
    }
}

fn status_name(s: Status) -> &'static str {
    match s {
        Status::New => "New",
        Status::InProgress => "InProgress",
        Status::Blocked => "Blocked",
        Status::Resolved => "Resolved",
        Status::Closed => "Closed",
    }
}

fn main() {
    let input = [
        "T1 assign:alice",
        "T1 start",
        "T1 resolve",
        "T1 close",
        "T2 close",
        "T2 assign:bob",
        "T2 start",
        "T2 block",
        "T2 resume",
        "T2 assign:carol",
        "T2 close",
        "T3 start",
        "T3 assign:dana",
        "T3 block",
        "T3 resolve",
        "T3 reopen",
    ];

    let mut tickets: BTreeMap<String, Ticket> = BTreeMap::new();

    for line in input {
