        ("C", &[Event::Create, Event::Resolve, Event::Resolve]),
        ("D", &[Event::Create, Event::Suspend, Event::Defer, Event::Resume]),
    ];

    let mut counts: BTreeMap<State, usize> = BTreeMap::new();
    let mut invalid = 0usize;

    for (_id, events) in scenarios {
        let mut state = None;
        for &event in events {
            let (next, ok) = apply_event(state, event);
            state = next;
            if !ok {
                invalid += 1;
            }
        }
        if let Some(s) = state {
            *counts.entry(s).or_insert(0) += 1;
        }
    }

    let ordered = [
        State::Active,
        State::Closed,
        State::Pending,
        State::Suspended,
        State::Reopened,
    ];

    for state in ordered {
        println!("{}: {}", label(state), counts.get(&state).copied().unwrap_or(0));
