  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "leaderboard_sort_rank_tiebreak_recovery"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
",
    "src/lib.rs": "use std::cmp::Ordering;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: String,
    pub score: u32,
    pub solved: u32,
    pub penalty: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: String,
    pub score: u32,
    pub solved: u32,
    pub penalty: u32,
}

fn cmp_player(a: &Player, b: &Player) -> Ordering {
    b.score
        .cmp(&a.score)
        .then_with(|| a.penalty.cmp(&b.penalty))
        .then_with(|| a.name.cmp(&b.name))
}

pub fn leaderboard(players: &[Player]) -> Vec<RankedPlayer> {
    let mut ordered = players.to_vec();
    ordered.sort_by(cmp_player);

    ordered
        .into_iter()
        .enumerate()
        .map(|(i, p)| RankedPlayer {
            rank: i + 1,
