    Edit { user_can_edit: bool, locked: bool },
    Delete { is_admin: bool, soft: bool },
    Share { external: bool, confirmed: bool },
}

pub fn decision(action: Action) -> &'static str {
    match action {
        Action::View { archived } => {
            if archived {
                "view"
            } else {
                "open"
            }
        }
        Action::Edit {
            user_can_edit,
            locked,
        } => {
            if user_can_edit {
                "edit"
            } else if locked {
                "request_unlock"
            } else {
                "readonly"
            }
        }
        Action::Delete { is_admin, soft } => {
            if is_admin || soft {
                "delete"
            } else {
                "forbidden"
            }
        }
        Action::Share {
            external,
            confirmed,
        } => {
            if external {
                "share_link"
            } else if confirmed {
                "share_internal"
            } else {
                "confirm_share"
            }
        }
    }
}

