pub struct Entry {
    pub id: u32,
    pub kind: String,
    pub active: bool,
}

pub fn parse_entry(input: &str) -> Result<Entry, String> {
    let mut id = None;
    let mut kind = None;
    let mut active = None;

    for part in input.split(',') {
        let mut it = part.split('=');
        let key = it.next().ok_or_else(|| "missing key".to_string())?.trim();
        let value = it.next().unwrap_or("").trim();

