    if let Some(level) = &env.log_level {
        merged.log_level = level.clone();
    }

    if let Some(tls) = env.use_tls {
        merged.use_tls = tls;
    } else if let Some(tls) = file.use_tls {
        merged.use_tls = tls;
    }

    merged
}

