pub struct Record {
    pub id: u32,
    pub kind: String,
    pub active: bool,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();

    for (line_no, raw_line) in input.lines().enumerate() {
        let line = raw_line.trim();
        if line.is_empty() {
            continue;
        }

        let mut id = None;
        let mut kind = None;
        let mut active = None;
        let mut tags = Vec::new();

        for part in line.split(';') {
            let piece = part.trim();
            if piece.is_empty() {
                continue;
            }
            let (key, value) = piece
                .split_once('=')
                .ok_or_else(|| format!("line {}: bad field", line_no + 1))?;
            let key = key.trim();
            let value = value.trim();
            match key {
                "id" => {
                    id = Some(value.parse::<u32>().map_err(|_| {
                        format!("line {}: invalid id", line_no + 1)
                    })?);
                }
                "kind" => {
                    kind = Some(value.to_string());
                }
                "active" => {
                    active = Some(match value {
                        "true" => true,
                        "false" => false,
                        _ => return Err(format!("line {}: invalid active", line_no + 1)),
                    });
                }
                "tags" => {
                    if !value.is_empty() {
                        tags = value
                            .split(',')
                            .map(|s| s.trim().to_string())
                            .collect();
                    }
                }
                _ => return Err(format!("line {}: unknown field {}", line_no + 1, key)),
            }
        }

        let id = id.ok_or_else(|| format!("line {}: missing id", line_no + 1))?;
        let kind = kind.ok_or_else(|| format!("line {}: missing kind", line_no + 1))?;
        let active = active.ok_or_else(|| format!("line {}: missing active", line_no + 1))?;

        out.push(Record {
            id,
            kind,
            active,
            tags,
        });
    }

    Ok(out)
}

