    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    InReview,
    Approved,
    Rejected,
    Published,
    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
    Publish,
    Archive,
    Restore,
}

pub fn apply_events(initial: Status, events: &[Event]) -> Status {
    let mut status = initial;
    for &event in events {
        status = step(status, event);
    }
    status
}

fn step(status: Status, event: Event) -> Status {
    use Event::*;
    use Status::*;

    match (status, event) {
        (Draft, Submit) => InReview,
        (InReview, Approve) => Approved,
        (InReview, Reject) => Rejected,
        (Rejected, Revise) => Draft,
        (Approved, Publish) => Published,
        (Published, Archive) => Archived,
        (Archived, Restore) => Draft,
        _ => status,
    }
}

#[cfg(test)]
mod tests {
