    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub id: u32,
    pub status: String,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (line_no, raw_line) in input.lines().enumerate() {
        let line = raw_line.trim();
        if line.is_empty() {
            continue;
        }

        let mut id = None;
        let mut status = String::new();
        let mut tags = Vec::new();

        for field in line.split(';') {
            let field = field.trim();
            if field.is_empty() {
                continue;
            }
            let (key, value) = field
                .split_once('=')
                .ok_or_else(|| format!("line {}: invalid field", line_no + 1))?;
            let key = key.trim();
            let value = value.trim();
            match key {
                "id" => {
                    id = Some(
                        value
                            .parse::<u32>()
                            .map_err(|_| format!("line {}: invalid id", line_no + 1))?,
                    );
                }
                "status" => status = value.to_string(),
                "tags" => {
                    tags = value
                        .split(',')
                        .filter(|s| !s.is_empty())
                        .map(|s| s.to_string())
                        .collect();
                }
                _ => return Err(format!("line {}: unknown key {}", line_no + 1, key)),
            }
        }

        let id = id.ok_or_else(|| format!("line {}: missing id", line_no + 1))?;
        out.push(Record { id, status, tags });
    }
    Ok(out)
}

