pub enum Action {
    Allow,
    Deny,
    Log(String),
}

pub fn decide(mode: Mode, flagged: bool, note: Option<&str>) -> Action {
    match mode {
        Mode::Fast => {
            if flagged {
                Action::Deny
            } else {
                Action::Allow
            }
        }
