    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    Active,
    Blocked,
    Done,
    Cancelled,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Complete,
    Cancel,
    Reopen,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub status: Status,
    pub touched: u32,
    pub blocked_count: u32,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            status: Status::New,
            touched: 0,
            blocked_count: 0,
        }
    }

    pub fn apply(&mut self, event: &Event) {
        match (&self.status, event) {
            (Status::New, Event::Start) => {
                self.status = Status::Active;
                self.touched += 1;
            }
            (Status::Active, Event::Block) => {
                self.status = Status::Blocked;
                self.blocked_count += 1;
                self.touched += 1;
            }
            (Status::Blocked, Event::Unblock) => {
                self.status = Status::Active;
                self.touched += 1;
            }
            (_, Event::Complete) => {
                self.status = Status::Done;
                self.touched += 1;
            }
            (_, Event::Cancel) => {
                self.status = Status::Cancelled;
                self.touched += 1;
            }
            (_, Event::Reopen) => {
                self.status = Status::Active;
                self.touched += 1;
            }
            _ => {}
        }
    }
}

pub fn run(events: &[Event]) -> Ticket {
    let mut ticket = Ticket::new();
    for e in events {
        ticket.apply(e);
    }
    ticket
}

