#[derive(Debug, Clone, PartialEq, Eq)]
pub struct EffectiveConfig {
    pub endpoint: String,
    pub token: String,
    pub retries: u32,
    pub verbose: bool,
}

fn choose_string(high: Option<String>, low: Option<String>, fallback: &str) -> String {
    high.or(low).unwrap_or_else(|| fallback.to_string())
}

fn choose_u32(high: Option<u32>, low: Option<u32>, fallback: u32) -> u32 {
    high.or(low).unwrap_or(fallback)
}

fn choose_bool(high: Option<bool>, low: Option<bool>, fallback: bool) -> bool {
    high.unwrap_or(low.unwrap_or(fallback))
}

pub fn merge_config(
    defaults: PartialConfig,
    file: PartialConfig,
    env: PartialConfig,
    cli: PartialConfig,
) -> EffectiveConfig {
    EffectiveConfig {
        endpoint: choose_string(defaults.endpoint, file.endpoint.or(env.endpoint), "https://localhost"),
        token: choose_string(defaults.token, file.token.or(env.token).or(cli.token), ""),
        retries: choose_u32(cli.retries, env.retries.or(file.retries).or(defaults.retries), 3),
