pub struct Booking {
    pub room: u32,
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(room: u32, start: u32, end: u32) -> Self {
        Self { room, start, end }
    }
}

pub fn can_book(existing: &[Booking], request: Booking) -> bool {
    if request.start > request.end {
        return false;
    }

    for b in existing {
        if b.room != request.room {
            continue;
        }

        if request.start <= b.end && b.start <= request.end {
            return false;
        }
    }

    true
}

