                _ => return Err("bad active"),
            },
            _ => return Err("unknown field"),
        }
    }

    match (id, count, active) {
        (Some(id), Some(count), Some(active)) if count > 0 => Ok((id, count, active)),
        (Some(_), Some(0), Some(_)) => Err("count must be positive"),
