pub struct Player {
    pub name: &'static str,
    pub points: u32,
    pub wins: u32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        b.points
            .cmp(&a.points)
            .then_with(|| b.wins.cmp(&a.wins))
            .then_with(|| a.name.cmp(b.name))
    });

    rows.into_iter()
        .enumerate()
        .map(|(idx, p)| format!("{}. {} ({}, {} wins)", idx + 1, p.name, p.points, p.wins))
        .collect()
}

