    "src/main.rs": "fn classify(line: &str) -> String {
    let trimmed = line.trim();
    if trimmed.is_empty() {
        return "skip".to_string();
    }

    let Some((key, value)) = trimmed.split_once('=') else {
        return format!("bad:{} reason=missing_equals", trimmed);
    };

    let key = key.trim();
    let value = value.trim();

    if key.is_empty() {
        return format!("bad:{} reason=empty_key", trimmed);
    }
    if value.parse::<u32>().is_err() {
        return format!("bad:{} reason=non_numeric_value", key);
    }

    format!("ok:{}={}", key, value)
}

fn main() {
    let input = "alice=42
bob=7
charlie=oops
 =5
eve
";

    let mut out = Vec::new();
    let mut valid = 0usize;
    let mut invalid = 0usize;

    for line in input.lines() {
        let status = classify(line);
        if status == "skip" {
            continue;
        }
        if status.starts_with("ok:") {
            valid += 1;
        } else {
            invalid += 1;
        }
        out.push(status);
    }

    println!("valid={} invalid={}", valid, invalid);
    for line in out {
        println!("{}", line);
    }
}
