{
  "family": "run_only",
  "case_id": "ticket_state_transition_audit_report",
  "bug_category": "state_transitions",
  "difficulty": "medium",
  "user": "Run the Rust crate at {project_root} and report the program's exact stdout.",
  "expected_tool_sequence": [
    "cargo_run"
  ],
  "expected_output": "T1=closed
T2=in_progress
T3=closed",
  "files": {
    "Cargo.toml": "[package]
name = "ticket_state_transition_audit_report"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum State {
    New,
    InProgress,
    Blocked,
    Closed,
}

enum Event<'a> {
    Create(&'a str),
    Start(&'a str),
    Block(&'a str),
    Unblock(&'a str),
    Resolve(&'a str),
    Reopen(&'a str),
}

fn apply(state: Option<State>, event: &Event<'_>) -> Option<State> {
    use Event::*;
    use State::*;

    match (state, event) {
        (None, Create(_)) => Some(New),
        (Some(New), Start(_)) => Some(InProgress),
        (Some(InProgress), Block(_)) => Some(Blocked),
        (Some(Blocked), Unblock(_)) => Some(InProgress),
        (Some(InProgress), Resolve(_)) | (Some(Blocked), Resolve(_)) => Some(Closed),
        (Some(Closed), Reopen(_)) => Some(InProgress),
        (s, _) => s,
    }
}

fn ticket_id(event: &Event<'_>) -> &str {
    match event {
        Event::Create(id)
        | Event::Start(id)
        | Event::Block(id)
        | Event::Unblock(id)
        | Event::Resolve(id)
        | Event::Reopen(id) => id,
    }
}

fn label(state: State) -> &'static str {
    match state {
        State::New => "new",
        State::InProgress => "in_progress",
        State::Blocked => "blocked",
        State::Closed => "closed",
    }
}

fn main() {
    let events = [
        Event::Create("T1"),
        Event::Resolve("T1"),
        Event::Start("T1"),
        Event::Resolve("T1"),
        Event::Create("T2"),
        Event::Start("T2"),
        Event::Block("T2"),
        Event::Unblock("T2"),
        Event::Create("T3"),
        Event::Start("T3"),
        Event::Resolve("T3"),
        Event::Reopen("T3"),
        Event::Resolve("T3"),
        Event::Block("T1"),
    ];

    let mut states: BTreeMap<&str, State> = BTreeMap::new();
    for event in &events {
        let id = ticket_id(event);
        let next = apply(states.get(id).copied(), event);
        if let Some(state) = next {
            states.insert(id, state);
        }
    }

    let mut out = Vec::new();
    for (id, state) in states {
        out.push(format!("{}={}", id, label(state)));
    }
    print!("{}", out.join("\n"));
}
"
  },
  "steps": [
    {
      "tool": "cargo_run",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: T1=closed
T2=in_progress
T3=closed"
}
